import { useState } from "react";

import InputForm from "../../Components/Input/InputForm";
import MainBtns from "../../Components/Buttons/MainBtns";

function PhotoPage() {
  const [image, setImage] = useState(null);
  const [text, setText] = useState("");
  const textareaRef = useRef(null);
  const maxLength = 200;

  const handleFileChange = (e) => {
    const file = e.target.files[0];
    if (file && file.type.startsWith("image/")) {
      const imageUrl = URL.createObjectURL(file);
      setImage(imageUrl);
    } else {
      setImage(null);
    }
  };


  return (
    <div className="page-root page-centered-column">

      <header className="page-header">
        <h2 className="header-title">Profile</h2>
        <span className="header-subtitle">Add info about yourself</span>
      </header>

      <div className="profile-container">
        <div className="basics">
          <span>Basics:</span>
          <InputForm TextPlaceholder={"Name"} zstyle={"mini-input"}/>
          <InputForm TextPlaceholder={"LastName"} zstyle={"mini-input"}/>
          <InputForm TextPlaceholder={"Role"} zstyle={"mini-input"}/>
        </div>

        <div className="biografy">
          <span>Biografy:</span>
          <textarea className="text-area" value={text} ref={textareaRef} placeholder="Biografy" onChange={(e) => setText(e.target.value)}/>
        </div>

        <div className="text-counter">
          {text.length} / {maxLength}
        </div>
      </div>

      <div className="save-row">
        <MainBtns Style={"purple-btn"} Text={"Save"} Width={"30%"} Funct={()=>{(text.length <= maxLength) ? console.log("true"): console.log("false")}} />
      </div>
    </div>
  );
}

export default PhotoPage;
